  function getArsenalBreakpointEncounterProfile(build, waveNumber) {
    if (
      !build ||
      !build.arsenalBreakpointProfileId ||
      !Number.isFinite(waveNumber) ||
      !isArsenalBreakpointWave(waveNumber)
    ) {
      return null;
    }
    return ARSENAL_BREAKPOINT_ENCOUNTER_PROFILES[build.arsenalBreakpointProfileId] || null;
  }

  function applyEncounterOverride(config, override) {
    if (!config || !override) {
      return config;
    }
    return {
      ...config,
      ...override,
      arena: override.arena || config.arena,
      mix: override.mix ? { ...override.mix } : { ...config.mix },
      hazard: sanitizeHazardForType(
        override.hazard
          ? {
              ...(config.hazard || {}),
              ...override.hazard,
            }
          : config.hazard
            ? { ...config.hazard }
            : null
      ),
    };
  }

  function getDirectLateBreakWaveOverride(index, build) {
    if (!build || !build.lateBreakProfileId) {
      return null;
    }
    if (index === LATE_BREAK_ARMORY_WAVE - 1) {
      return getLateBreakEncounterProfile(build);
    }
    if (index === LATE_BREAK_ARMORY_WAVE) {
      return getLateBreakFollowthroughProfile(build);
    }
    return null;
  }

  function resolveWaveConfig(index, build = null) {
    const baseConfig = WAVE_CONFIG[clamp(index, 0, MAX_WAVES - 1)];
    if (!baseConfig || index < LATE_BREAK_ARMORY_WAVE - 1 || !build) {
      return applySupportProofEncounterConfig(
        applyChassisBreakpointEncounterConfig(
          applyEncounterPressureFamily(baseConfig),
          build,
          index + 1
        ),
        build,
        index + 1
      );
    }
    const directLateBreakOverride = getDirectLateBreakWaveOverride(index, build);
    const override =
      directLateBreakOverride || SHARED_LATE_ACT_ENCOUNTER_POOL[index] || null;
    if (!override) {
      return applySupportProofEncounterConfig(
        applyChassisBreakpointEncounterConfig(
          applyEncounterPressureFamily(baseConfig),
          build,
          index + 1
        ),
        build,
        index + 1
      );
    }
    let config = applyEncounterOverride(baseConfig, override);
    const arsenalBreakpointProfile = getArsenalBreakpointEncounterProfile(build, index + 1);
    if (arsenalBreakpointProfile) {
      config = applyEncounterOverride(config, arsenalBreakpointProfile);
    }
    return applySupportProofEncounterConfig(
      applyChassisBreakpointEncounterConfig(
        applyEncounterPressureFamily(config),
        build,
        index + 1
      ),
      build,
      index + 1
    );
  }

  function getActLabelForWave(waveNumber) {
    const act = ACT_LABELS.find((entry) => waveNumber >= entry.start && waveNumber <= entry.end);
    return act || ACT_LABELS[ACT_LABELS.length - 1];
  }

  function getPlayerFacingActLabelForWave(waveNumber) {
    const boundedWave = CONSOLIDATED_12_WAVE_ROUTE
      ? clamp(Math.round(waveNumber || 1), 1, DEFAULT_ROUTE_WAVE_COUNT)
      : waveNumber;
    return getActLabelForWave(boundedWave);
  }

