  function createForgeSpotlightMarkup(choices) {
    if (!Array.isArray(choices) || choices.length === 0) {
      return "";
    }
    return `
      <div class="forge-spotlight-grid">
        ${choices
          .slice(0, 3)
          .map((choice) => {
            const transformation = getForgeChoiceTransformation(choice);
            return `
              <article class="forge-spotlight forge-spotlight--${transformation.tone}">
                <p class="panel__eyebrow">${choice.contractLabel || transformation.laneLabel}</p>
                <strong>${transformation.title}</strong>
                <p class="forge-spotlight__promise">${transformation.promise}</p>
                <p class="summary-note">${transformation.proof}</p>
                <p class="summary-note">мґФм≤Ь rider ¬Ј ${transformation.riderLabel}</p>
              </article>
            `;
          })
          .join("")}
      </div>
    `;
  }

  function clonePreviewBuild(build) {
    return build ? JSON.parse(JSON.stringify(build)) : null;
  }

  function createForgePreviewRun(build) {
    if (!build) {
      return null;
    }
    const previewBuild = clonePreviewBuild(build);
    return {
      build: previewBuild,
      resources: { scrap: 999, scrapCollected: 0, scrapSpent: 0 },
      stats: { kills: 0, coresCollected: 0, scrapCollected: 0, scrapSpent: 0 },
      player: {
        hp: Math.max(1, 100 + (previewBuild.maxHpBonus || 0)),
        maxHp: Math.max(1, 100 + (previewBuild.maxHpBonus || 0)),
        heat: 0,
        overheated: false,
        invulnerableTime: 0,
      },
    };
  }

  function getWeaponFormLabel(weapon) {
    if (!weapon) {
      return "Unknown Form";
    }
    return getPresentationHeadlineLabel(weapon);
  }

  function shouldUseShippingRoutePresentation(waveNumber = 1) {
    const boundedWave = clamp(
      Math.round(waveNumber || 1),
      1,
      MAX_WAVES + POST_CAPSTONE_WAVE_COUNT
    );
    return CONSOLIDATED_12_WAVE_ROUTE && boundedWave <= MAX_WAVES;
  }

  function getPresentationHeadlineLabel(weapon, waveNumber = 1) {
    if (!weapon) {
      return "Unknown Form";
    }
    if (shouldUseShippingRoutePresentation(waveNumber)) {
      return (
        weapon.headlineFormLabel ||
        weapon.lateAscensionLabel ||
        weapon.capstoneLabel ||
        weapon.doctrineFormLabel ||
        weapon.evolutionLabel ||
        (weapon.core ? weapon.core.label : "Base Frame")
      );
    }
    return (
      weapon.headlineFormLabel ||
      weapon.afterburnDominionLabel ||
      weapon.afterburnOverdriveLabel ||
      weapon.lateAscensionLabel ||
      weapon.lateFieldConvergenceLabel ||
      weapon.capstoneLabel ||
      weapon.doctrineFormLabel ||
      weapon.afterglowMutationLabel ||
      weapon.evolutionLabel ||
      (weapon.core ? weapon.core.label : "Base Frame")
    );
  }

  function getPresentationFormDetail(build, weapon, waveNumber = 1) {
    const activeCore = CORE_DEFS[build.coreId];
    if (shouldUseShippingRoutePresentation(waveNumber)) {
      return (
        weapon.lateAscensionStatusNote ||
        weapon.lateBreakStatusNote ||
        (getClaimedWildcardProtocolIds(build).includes("rogue_lattice")
        ? weapon.lateFieldConvergenceStatusNote || weapon.lateFieldMutationStatusNote
        : null) ||
        weapon.capstoneStatusNote ||
        weapon.doctrineStatusNote ||
        weapon.afterglowMutationStatusNote ||
        weapon.evolutionStatusNote ||
        `${activeCore.label} ${weapon.tierLabel} нФДл†ИмЮДмЭі нШДмЮђ м£Љл†•мЭілЛ§.`
      );
    }
    return (
      weapon.afterburnDominionStatusNote ||
      weapon.afterburnOverdriveStatusNote ||
      weapon.lateAscensionStatusNote ||
      weapon.lateBreakStatusNote ||
      (getClaimedWildcardProtocolIds(build).includes("rogue_lattice")
        ? weapon.lateFieldConvergenceStatusNote || weapon.lateFieldMutationStatusNote
        : null) ||
      weapon.capstoneStatusNote ||
      weapon.doctrineStatusNote ||
      weapon.evolutionStatusNote ||
      `${activeCore.label} ${weapon.tierLabel} нФДл†ИмЮДмЭі нШДмЮђ м£Љл†•мЭілЛ§.`
    );
  }

  function getWeaponEchoCount(weapon) {
    if (!weapon) {
      return 0;
    }
    const patternCounts = [
      weapon.lateFieldMutationFirePattern &&
      Array.isArray(weapon.lateFieldMutationFirePattern.offsets)
        ? weapon.lateFieldMutationFirePattern.offsets.length
        : 0,
      weapon.riskMutationFirePattern &&
      Array.isArray(weapon.riskMutationFirePattern.offsets)
        ? weapon.riskMutationFirePattern.offsets.length
        : 0,
      weapon.apexMutationFirePattern &&
      Array.isArray(weapon.apexMutationFirePattern.offsets)
        ? weapon.apexMutationFirePattern.offsets.length
        : 0,
      weapon.afterburnDominionFirePattern &&
      Array.isArray(weapon.afterburnDominionFirePattern.offsets)
      ? weapon.afterburnDominionFirePattern.offsets.length
        : 0,
      weapon.afterglowMutationFirePattern &&
      Array.isArray(weapon.afterglowMutationFirePattern.offsets)
        ? weapon.afterglowMutationFirePattern.offsets.length
        : 0,
      weapon.crownfireOverdriveFirePattern &&
      Array.isArray(weapon.crownfireOverdriveFirePattern.offsets)
        ? weapon.crownfireOverdriveFirePattern.offsets.length
        : 0,
    ];
    return Math.max(...patternCounts, 0);
  }

  function describeWeaponVolley(weapon) {
    if (!weapon || !weapon.core) {
      return "нЩФлІЭ лѓЄнЩХмЭЄ";
    }
    if (weapon.core.id === "scatter") {
      return `${weapon.pellets}нО†л¶њ нЩХмВ∞`;
    }
    if (weapon.core.id === "lance") {
      return `кіАнЖµ ${weapon.pierce} л†ИмЭЉ`;
    }
    if (weapon.core.id === "ricochet") {
      return `л∞ШмВђ ${weapon.bounce} / мЧ∞мЗД ${weapon.chain}`;
    }
    return `мЧ∞мВђ ${(1 / Math.max(weapon.cooldown || 1, 0.08)).toFixed(1)}/s`;
  }

  function describeWeaponBattery(weapon) {
    if (!weapon) {
      return "л≥ім°∞ нПђлђЄ мЧЖмЭМ";
    }
    if (weapon.lateFieldBroadsideConfig) {
      return `лЄМл°ЬлУЬмВђмЭілУЬ нПђлУЬ ${weapon.lateFieldBroadsideConfig.podCount}`;
    }
    const echoCount = getWeaponEchoCount(weapon);
    if (echoCount > 0) {
      return `мЧРмљФ л∞∞лЯі ${echoCount}`;
    }
    if (weapon.chain > 0) {
      return `мЧ∞мЗД л∞Шк≤љ ${Math.round(weapon.chainRange || 0)}`;
    }
    return `нГДмЖН ${Math.round(weapon.projectileSpeed || 0)}`;
  }

  function formatHeadlineDeltaRow(label, beforeValue, afterValue) {
    if (!beforeValue && !afterValue) {
      return null;
    }
    return {
      label,
      value:
        beforeValue && beforeValue !== afterValue
          ? `${beforeValue} -> ${afterValue}`
          : afterValue || beforeValue,
    };
  }

  function getForgeHeadlineShowcase(choice, build, waveNumber = 1) {
    if (!choice || !build) {
      return null;
    }
    const previewRun = createForgePreviewRun(build);
    if (!previewRun) {
      return null;
    }
    const beforeWeapon = computeWeaponStats(build);
    const beforeSupport = getForgeSupportTrackSnapshot(build);
    const appliedChoice = applyForgeChoice(previewRun, {
      ...choice,
      cost: 0,
    });
    if (!appliedChoice) {
      return null;
    }
    const afterWeapon = computeWeaponStats(previewRun.build);
    const afterSupport = getForgeSupportTrackSnapshot(previewRun.build);
    const transformation = getForgeChoiceTransformation(choice);
    const nextProof = getImmediateProofWindowSummary(previewRun.build, waveNumber);
    const rows = [
      formatHeadlineDeltaRow("Form", getWeaponFormLabel(beforeWeapon), getWeaponFormLabel(afterWeapon)),
      formatHeadlineDeltaRow("Volley", describeWeaponVolley(beforeWeapon), describeWeaponVolley(afterWeapon)),
      formatHeadlineDeltaRow("Battery", describeWeaponBattery(beforeWeapon), describeWeaponBattery(afterWeapon)),
      formatHeadlineDeltaRow("Rider", beforeSupport.label, afterSupport.label),
    ]
      .filter(Boolean)
      .slice(0, 3);
    const headlineChanged = rows.some((row) => row.value.includes("->"));
    const score =
      (getForgeChoiceTone(choice) === "main" ? 1000 : 0) +
      (headlineChanged ? 180 : 0) +
      Math.abs((afterWeapon.pellets || 0) - (beforeWeapon.pellets || 0)) * 120 +
      Math.abs((afterWeapon.pierce || 0) - (beforeWeapon.pierce || 0)) * 100 +
      Math.abs((afterWeapon.chain || 0) - (beforeWeapon.chain || 0)) * 90 +
      Math.abs((afterWeapon.bounce || 0) - (beforeWeapon.bounce || 0)) * 90 +
      Math.abs(getWeaponEchoCount(afterWeapon) - getWeaponEchoCount(beforeWeapon)) * 70 +
      Math.abs(
        ((afterWeapon.lateFieldBroadsideConfig && afterWeapon.lateFieldBroadsideConfig.podCount) || 0) -
          ((beforeWeapon.lateFieldBroadsideConfig && beforeWeapon.lateFieldBroadsideConfig.podCount) || 0)
      ) *
        120;
    return {
      choice,
      transformation,
      rows,
      proofLabel: nextProof.label,
      proofDetail: nextProof.detail,
      score,
    };
  }

  function pickForgeHeadlineShowcase(choices, build, waveNumber = 1) {
    if (!Array.isArray(choices) || choices.length === 0 || !build) {
      return null;
    }
    return choices
      .map((choice) => getForgeHeadlineShowcase(choice, build, waveNumber))
      .filter(Boolean)
      .sort((left, right) => right.score - left.score)[0] || null;
  }

  function createForgeHeadlineShowcaseMarkup(showcase) {
    if (!showcase) {
      return "";
    }
    return `
      <article class="forge-headline-showcase forge-headline-showcase--${showcase.transformation.tone}">
        <div class="forge-headline-showcase__header">
          <p class="panel__eyebrow">Monster Form Promise</p>
          <span class="forge-headline-showcase__tag">${showcase.choice.contractLabel || showcase.transformation.laneLabel}</span>
        </div>
        <strong>${showcase.choice.title}</strong>
        <p class="forge-headline-showcase__promise">${showcase.transformation.promise}</p>
        <div class="forge-headline-showcase__grid">
          ${showcase.rows
            .map(
              (row) => `
                <article class="forge-headline-showcase__cell">
                  <span>${row.label}</span>
                  <strong>${row.value}</strong>
                </article>
              `
            )
            .join("")}
        </div>
        <p class="summary-note">${showcase.proofLabel}. ${showcase.transformation.proof}</p>
      </article>
    `;
  }

  function getForgeFeaturedChoice(choices, build, waveNumber = 1) {
    const showcase = pickForgeHeadlineShowcase(choices, build, waveNumber);
    if (!showcase) {
      return { showcase: null, featuredIndex: -1 };
    }
    const featuredIndex = Array.isArray(choices)
      ? choices.findIndex(
          (choice) =>
            choice === showcase.choice ||
            (choice && showcase.choice && choice.id && choice.id === showcase.choice.id)
        )
      : -1;
    return {
      showcase,
      featuredIndex,
    };
  }

  function getBenchCount(build, coreId) {
    if (!build || !Array.isArray(build.pendingCores)) {
      return 0;
    }
    return build.pendingCores.reduce(
      (total, storedCoreId) => total + (storedCoreId === coreId ? 1 : 0),
      0
    );
  }

  function getBenchSyncLevel(build, coreId) {
    return clamp(getBenchCount(build, coreId) - 1, 0, 3);
  }

  function formatSyncLabel(level) {
    if (level >= 3) {
      return "3к∞Х";
    }
    if (level >= 2) {
      return "2к∞Х";
    }
    if (level >= 1) {
      return "1к∞Х";
    }
    return "0к∞Х";
  }

  function getBenchEntries(build) {
    const counts = {};
    const benchCoreIds = sanitizeBenchCoreIds(
      build && Array.isArray(build.pendingCores) ? build.pendingCores : []
    );
    for (const coreId of benchCoreIds) {
      counts[coreId] = (counts[coreId] || 0) + 1;
    }
    return Object.entries(counts)
      .map(([coreId, copies]) => ({
        coreId,
        copies,
        syncLevel: getBenchSyncLevel({ pendingCores: benchCoreIds }, coreId),
      }))
      .sort((left, right) => {
        if (right.copies !== left.copies) {
          return right.copies - left.copies;
        }
        return CORE_DEFS[left.coreId].label.localeCompare(CORE_DEFS[right.coreId].label);
      });
  }

  function summarizeBenchCoreIds(coreIds) {
    const counts = {};
    for (const coreId of sanitizeBenchCoreIds(coreIds)) {
      counts[coreId] = (counts[coreId] || 0) + 1;
    }
    return Object.entries(counts)
      .map(([coreId, copies]) => `${CORE_DEFS[coreId].short} x${copies}`)
      .join(" / ");
  }

  function addBenchCore(build, coreId) {
    if (!build || !CORE_DEFS[coreId]) {
      return false;
    }
    if (getBenchCount(build, coreId) >= MAX_BENCH_COPIES_PER_CORE) {
      return false;
    }
    build.pendingCores = sanitizeBenchCoreIds(build.pendingCores.concat(coreId));
    return true;
  }

  function removeBenchCopies(build, coreId, count) {
    if (!build || !Array.isArray(build.pendingCores) || !CORE_DEFS[coreId]) {
      return 0;
    }
    let remaining = Math.max(0, count || 0);
    let removed = 0;
    const next = [];
    for (const storedCoreId of build.pendingCores) {
      if (storedCoreId === coreId && remaining > 0) {
        remaining -= 1;
        removed += 1;
        continue;
      }
      next.push(storedCoreId);
    }
    build.pendingCores = sanitizeBenchCoreIds(next);
    return removed;
  }

  function pickLeanStartBiasDoctrineId(random = Math.random) {
    const doctrineIds = LEAN_START_BIAS_DOCTRINE_IDS.filter((doctrineId) => BASTION_DOCTRINE_DEFS[doctrineId]);
    if (doctrineIds.length === 0) {
      return null;
    }
    const clampedRoll = clamp(random(), 0, 0.999999);
    return doctrineIds[Math.floor(clampedRoll * doctrineIds.length)] || doctrineIds[0];
  }

  function createInitialBuild(signatureId = DEFAULT_SIGNATURE_ID, options = {}) {
    return sanitizeConsolidatedBuildState(applySignatureToBuild(
      {
        signatureId: BASE_BUILD.signatureId,
        coreId: BASE_BUILD.coreId,
        attunedCoreId: BASE_BUILD.attunedCoreId,
        attunedCopies: BASE_BUILD.attunedCopies,
        affixes: BASE_BUILD.affixes.slice(),
        finisherCatalysts: BASE_BUILD.finisherCatalysts.slice(),
        catalystCapstoneId: BASE_BUILD.catalystCapstoneId,
        cashoutSupportId: BASE_BUILD.cashoutSupportId,
        cashoutFailSoftId: BASE_BUILD.cashoutFailSoftId,
        act3CatalystDraftSeen: BASE_BUILD.act3CatalystDraftSeen,
        architectureForecastId: BASE_BUILD.architectureForecastId,
        leanStartBiasDoctrineId: BASE_BUILD.leanStartBiasDoctrineId,
        bastionDoctrineId: BASE_BUILD.bastionDoctrineId,
        doctrineCapstoneId: BASE_BUILD.doctrineCapstoneId,
        afterburnAscensionOffered: BASE_BUILD.afterburnAscensionOffered,
        afterburnOverdriveId: BASE_BUILD.afterburnOverdriveId,
        afterburnDominionId: BASE_BUILD.afterburnDominionId,
        afterburnDominionVictoryLapWaves: BASE_BUILD.afterburnDominionVictoryLapWaves,
        lateAscensionId: BASE_BUILD.lateAscensionId,
        lateAscensionOffered: BASE_BUILD.lateAscensionOffered,
        doctrineChaseClaimed: BASE_BUILD.doctrineChaseClaimed,
        doctrinePursuitCommitted: BASE_BUILD.doctrinePursuitCommitted,
        doctrinePursuitProgress: BASE_BUILD.doctrinePursuitProgress,
        doctrinePursuitExpired: BASE_BUILD.doctrinePursuitExpired,
        overcommitUnlocked: BASE_BUILD.overcommitUnlocked,
        overcommitResolved: BASE_BUILD.overcommitResolved,
        illegalOverclockId: BASE_BUILD.illegalOverclockId,
        illegalOverclockOffered: BASE_BUILD.illegalOverclockOffered,
        illegalOverclockMutationLevel: BASE_BUILD.illegalOverclockMutationLevel,
        crownfireOverdriveId: BASE_BUILD.crownfireOverdriveId,
        riskMutationLevel: BASE_BUILD.riskMutationLevel,
        riskMutationQueuedLevel: BASE_BUILD.riskMutationQueuedLevel,
        apexMutationLevel: BASE_BUILD.apexMutationLevel,
        predatorBaitCharges: BASE_BUILD.predatorBaitCharges,
        wildcardProtocolIds: BASE_BUILD.wildcardProtocolIds.slice(),
        lateFieldMutationLevel: BASE_BUILD.lateFieldMutationLevel,
        lateFieldAegisLevel: BASE_BUILD.lateFieldAegisLevel,
        lateFieldConvergenceId: BASE_BUILD.lateFieldConvergenceId,
        lateBreakProfileId: BASE_BUILD.lateBreakProfileId,
        arsenalBreakpointProfileId: BASE_BUILD.arsenalBreakpointProfileId,
        midrunGreedRouteUntilWave: BASE_BUILD.midrunGreedRouteUntilWave,
        blackLedgerRaidWaves: BASE_BUILD.blackLedgerRaidWaves,
        bastionPactDebtWaves: BASE_BUILD.bastionPactDebtWaves,
        wave6ChassisBreakpoint: BASE_BUILD.wave6ChassisBreakpoint,
        chassisId: BASE_BUILD.chassisId,
        supportBayCap: BASE_BUILD.supportBayCap,
        auxiliaryJunctionLevel: BASE_BUILD.auxiliaryJunctionLevel,
        supportSystemId: BASE_BUILD.supportSystemId,
        supportSystemTier: BASE_BUILD.supportSystemTier,
        supportSystems: BASE_BUILD.supportSystems.slice(),
        weaponEvolutions: { ...BASE_BUILD.weaponEvolutions },
        pendingCores: [],
        upgrades: [],
        damageBonus: BASE_BUILD.damageBonus,
        cooldownBonus: BASE_BUILD.cooldownBonus,
        pierceBonus: BASE_BUILD.pierceBonus,
        chainBonus: BASE_BUILD.chainBonus,
        heatFactor: BASE_BUILD.heatFactor,
        coolRateBonus: BASE_BUILD.coolRateBonus,
        moveSpeedBonus: BASE_BUILD.moveSpeedBonus,
        pickupBonus: BASE_BUILD.pickupBonus,
        dashCooldownBonus: BASE_BUILD.dashCooldownBonus,
        dashMaxBonus: BASE_BUILD.dashMaxBonus,
        maxHpBonus: BASE_BUILD.maxHpBonus,
        scrapMultiplier: BASE_BUILD.scrapMultiplier,
        driveGainBonus: BASE_BUILD.driveGainBonus,
        overdriveDurationBonus: BASE_BUILD.overdriveDurationBonus,
        hazardMitigation: BASE_BUILD.hazardMitigation,
      },
      signatureId,
      options
    ));
  }

  function applySignatureToBuild(build, signatureId, options = {}) {
    const nextBuild = build || {};
    const signature =
      SIGNATURE_DEFS[signatureId] || SIGNATURE_DEFS[DEFAULT_SIGNATURE_ID];
    const leanStartContract = CONSOLIDATED_12_WAVE_ROUTE;
    const leanStartBiasDoctrine = leanStartContract
      ? getBastionDoctrineDef(options.leanStartBiasDoctrineId)
      : null;
    const leanStartSeedCoreId =
      leanStartBiasDoctrine && leanStartBiasDoctrine.favoredCoreId && CORE_DEFS[leanStartBiasDoctrine.favoredCoreId]
        ? leanStartBiasDoctrine.favoredCoreId
        : null;
    const starterCoreId = leanStartContract
      ? LEAN_START_CORE_ID
      : signature.startCoreId || nextBuild.coreId || BASE_BUILD.coreId;
    nextBuild.signatureId = leanStartContract ? null : signature.id;
    nextBuild.coreId = starterCoreId;
    nextBuild.leanStartBiasDoctrineId = leanStartContract && leanStartBiasDoctrine
      ? leanStartBiasDoctrine.id
      : null;
    nextBuild.attunedCoreId = nextBuild.coreId;
    nextBuild.attunedCopies = 1;
    nextBuild.affixes = sanitizeAffixIds(
      (Array.isArray(nextBuild.affixes) ? nextBuild.affixes : []).concat(
        leanStartContract ? [] : signature.startAffixes || []
      ),
      getAffixCapacity(nextBuild)
    );
    nextBuild.pendingCores = sanitizeBenchCoreIds(
      (Array.isArray(nextBuild.pendingCores) ? nextBuild.pendingCores : []).concat(
        leanStartContract
          ? leanStartSeedCoreId && leanStartSeedCoreId !== starterCoreId
            ? [leanStartSeedCoreId]
            : []
          : signature.seedCores || []
      )
    );
    if (!leanStartContract && typeof signature.apply === "function") {
      signature.apply(nextBuild);
    }
    nextBuild.upgrades = leanStartContract
      ? Array.isArray(nextBuild.upgrades)
        ? nextBuild.upgrades.slice()
        : []
      : [`мЛЬкЈЄлЛИм≤Ш: ${signature.label}`].concat(
          Array.isArray(nextBuild.upgrades) ? nextBuild.upgrades : []
        );
    return sanitizeConsolidatedBuildState(nextBuild);
  }

  function sanitizeConsolidatedBuildState(build) {
    if (!CONSOLIDATED_12_WAVE_ROUTE || !build) {
      return build;
    }
    if (build.doctrineChaseClaimed) {
      build.doctrineChaseClaimed = false;
    }
    if (build.doctrinePursuitCommitted) {
      build.doctrinePursuitCommitted = false;
    }
    if (build.doctrinePursuitProgress) {
      build.doctrinePursuitProgress = 0;
    }
    if (build.doctrinePursuitExpired) {
      build.doctrinePursuitExpired = false;
    }
    if (build.overcommitUnlocked) {
      build.overcommitUnlocked = false;
    }
    if (build.overcommitResolved) {
      build.overcommitResolved = false;
    }
    if (Array.isArray(build.upgrades) && build.upgrades.length > 0) {
      build.upgrades = build.upgrades.filter(
        (entry) =>
          typeof entry !== "string" ||
          (!entry.includes("кµРл¶ђ мґФк≤©") &&
            !entry.includes("Forge Pursuit") &&
            !entry.includes("Contraband Overcommit") &&
            !entry.startsWith("Ascension Relay:"))
      );
    }
    if (
      build.previewSupportSystemId &&
      PREVIEW_SUPPORT_SYSTEM_DEFS[build.previewSupportSystemId]
    ) {
      build.previewSupportSystemId = null;
    }
    if (Array.isArray(build.wildcardProtocolIds) && build.wildcardProtocolIds.length > 0) {
      build.wildcardProtocolIds = [];
    }
    if (build.lateBreakProfileId) {
      build.lateBreakProfileId = null;
    }
    if (build.lateAscensionId) {
      build.lateAscensionId = null;
    }
    if (build.lateAscensionOffered) {
      build.lateAscensionOffered = false;
    }
    if (build.afterburnAscensionOffered) {
      build.afterburnAscensionOffered = false;
    }
    if (build.afterburnOverdriveId) {
      build.afterburnOverdriveId = null;
    }
    if (build.afterburnDominionId) {
      build.afterburnDominionId = null;
    }
    if (build.afterburnDominionVictoryLapWaves) {
      build.afterburnDominionVictoryLapWaves = 0;
    }
    if (build.illegalOverclockId) {
      build.illegalOverclockId = null;
    }
    if (build.illegalOverclockOffered) {
      build.illegalOverclockOffered = false;
    }
    if (build.illegalOverclockMutationLevel) {
      build.illegalOverclockMutationLevel = 0;
    }
    if (build.riskMutationLevel) {
      build.riskMutationLevel = 0;
    }
    if (build.riskMutationQueuedLevel) {
      build.riskMutationQueuedLevel = 0;
    }
    if (build.apexMutationLevel) {
      build.apexMutationLevel = 0;
    }
    if (build.predatorBaitCharges) {
      build.predatorBaitCharges = 0;
    }
    if (build.lateFieldMutationLevel) {
      build.lateFieldMutationLevel = 0;
    }
    if (build.lateFieldAegisLevel) {
      build.lateFieldAegisLevel = 0;
    }
    if (build.lateFieldConvergenceId) {
      build.lateFieldConvergenceId = null;
    }
    if (build.arsenalBreakpointProfileId) {
      build.arsenalBreakpointProfileId = null;
    }
    if (build.blackLedgerRaidWaves) {
      build.blackLedgerRaidWaves = 0;
    }
    build.supportBayCap = clamp(
      Math.round(build.supportBayCap || getStartingSupportBayCapacity()),
      getStartingSupportBayCapacity(),
      getOwnershipSupportBayCapacityTarget(build)
    );
    return build;
  }

  function getSanitizedConsolidatedBuild(build) {
    if (!CONSOLIDATED_12_WAVE_ROUTE || !build) {
      return build;
    }
    const sanitizedBuild = {
      ...build,
      wildcardProtocolIds: Array.isArray(build.wildcardProtocolIds)
        ? build.wildcardProtocolIds.slice()
        : [],
    };
    return sanitizeConsolidatedBuildState(sanitizedBuild);
  }

  function getSignatureDef(signatureId) {
    return SIGNATURE_DEFS[signatureId] || SIGNATURE_DEFS[DEFAULT_SIGNATURE_ID];
  }

  function getTitleRouteSignatureId() {
    return CONSOLIDATED_12_WAVE_ROUTE ? null : selectedSignatureId;
  }

  function getBastionDoctrineDef(buildOrSignatureId) {
    if (!buildOrSignatureId) {
      return null;
    }
    if (typeof buildOrSignatureId === "object" && buildOrSignatureId.bastionDoctrineId) {
      const adoptedDoctrine = Object.values(BASTION_DOCTRINE_DEFS).find(
        (doctrine) => doctrine.id === buildOrSignatureId.bastionDoctrineId
      );
      if (adoptedDoctrine) {
        return adoptedDoctrine;
      }
    }
    if (typeof buildOrSignatureId === "object" && buildOrSignatureId.architectureForecastId) {
      const forecastDoctrine = Object.values(BASTION_DOCTRINE_DEFS).find(
        (doctrine) => doctrine.id === buildOrSignatureId.architectureForecastId
      );
      if (forecastDoctrine) {
        return forecastDoctrine;
      }
    }
    if (typeof buildOrSignatureId === "string") {
      const directDoctrine = Object.values(BASTION_DOCTRINE_DEFS).find(
        (doctrine) => doctrine.id === buildOrSignatureId
      );
      if (directDoctrine) {
        return directDoctrine;
      }
    }
    const signatureId =
      typeof buildOrSignatureId === "string"
        ? buildOrSignatureId
        : buildOrSignatureId.signatureId || null;
    return signatureId ? BASTION_DOCTRINE_DEFS[signatureId] || null : null;
  }

  function getLeanStartBiasDoctrineDef(build) {
    if (!build || !build.leanStartBiasDoctrineId) {
      return null;
    }
    return getBastionDoctrineDef(build.leanStartBiasDoctrineId);
  }

  function getDoctrineCapstoneDef(buildOrCapstoneId) {
    if (!buildOrCapstoneId) {
      return null;
    }
    if (typeof buildOrCapstoneId === "object") {
      return buildOrCapstoneId.doctrineCapstoneId
        ? Object.values(DOCTRINE_CAPSTONE_DEFS).find(
            (capstone) => capstone.id === buildOrCapstoneId.doctrineCapstoneId
          ) || null
        : null;
    }
    return (
      Object.values(DOCTRINE_CAPSTONE_DEFS).find((capstone) => capstone.id === buildOrCapstoneId) ||
      DOCTRINE_CAPSTONE_DEFS[buildOrCapstoneId] ||
      null
    );
  }

  function getDoctrineLateCapstoneDefs(buildOrDoctrine) {
    const doctrine = getBastionDoctrineDef(buildOrDoctrine);
    if (!doctrine) {
      return [];
    }
    const capstoneIds = Array.isArray(doctrine.lateCapstoneIds) && doctrine.lateCapstoneIds.length > 0
      ? doctrine.lateCapstoneIds
      : doctrine.lateCapstoneId
        ? [doctrine.lateCapstoneId]
        : [];
    return capstoneIds
      .map((capstoneId) => getDoctrineCapstoneDef(capstoneId))
      .filter(Boolean);
  }

  function getDoctrineLateCapstoneLabel(buildOrDoctrine) {
    const capstones = getDoctrineLateCapstoneDefs(buildOrDoctrine);
    if (capstones.length === 0) {
      return null;
    }
    return capstones.map((capstone) => capstone.title).join(" / ");
  }

  function getDoctrinePursuitCapstoneDef(buildOrDoctrine) {
    const doctrine = getBastionDoctrineDef(buildOrDoctrine);
    const capstones = getDoctrineLateCapstoneDefs(doctrine);
    if (!doctrine || capstones.length === 0) {
      return null;
    }
    if (capstones.length === 1) {
      return capstones[0];
    }
    if (doctrine.id === "storm_artillery") {
      const build = typeof buildOrDoctrine === "object" ? buildOrDoctrine : null;
      const affixes = build && Array.isArray(build.affixes) ? build.affixes : [];
      const pierceWeight =
        (build && (build.pierceBonus || 0)) +
        (affixes.includes("phase_rounds") ? 2 : 0) +
        ((build && build.coreId === "lance") ? 1 : 0);
      return (
        getDoctrineCapstoneDef(pierceWeight >= 3 ? "stormspire_needle" : "sky_lance_battery") ||
        capstones[0]
      );
    }
    return capstones[0];
  }

  function getDoctrineForgePursuitDef(buildOrDoctrineId) {
    if (!buildOrDoctrineId) {
      return null;
    }
    const doctrineId =
      typeof buildOrDoctrineId === "object"
        ? buildOrDoctrineId.bastionDoctrineId || buildOrDoctrineId.id
        : buildOrDoctrineId;
    return doctrineId ? DOCTRINE_FORGE_PURSUIT_DEFS[doctrineId] || null : null;
  }

  function getStormArtilleryAfterburnEndform(buildOrCapstoneId) {
    const capstone = getDoctrineCapstoneDef(buildOrCapstoneId);
    if (!capstone || capstone.doctrineId !== "storm_artillery") {
      return null;
    }
    return STORM_ARTILLERY_AFTERBURN_ENDFORM_DEFS[capstone.id] || null;
  }

  function createRoadmapStep(label, title, detail, stateName = "planned") {
    return {
      label,
      title,
      detail,
      state: stateName,
    };
  }

  function getShippingRouteCapstoneRoadmap(build, stageTwoTitle, boundedWave) {
    if (build.doctrineCapstoneId) {
      return {
        detail: `${stageTwoTitle}мЭі(к∞А) мЭілѓЄ мЮ†к≤ЉлЛ§. Wave 9-10мЭА мГИ к∞Ил¶ЉкЄЄ мЧЖмЭі мЭі нШХнГЬл°Ь мЧіл¶∞ laneмЭД л®Љм†А л®єк≥† crownlineкєМмІА л∞АмЦілґЩмЭілКФ кµђк∞ДмЭілЛ§.`,
        state: "locked",
      };
    }
    if (boundedWave >= 7) {
      return {
        detail: `${stageTwoTitle}лІМ лВ®мХШлЛ§. Wave 9 open-laneмЧР лУ§мЦік∞АкЄ∞ м†ДкєМмІА нЩФлІЭмЭілВШ л™Єм≤і л¶ђлУђмЭД нХЬ л≤И лНФ нВ§мЫМ crownline pressureл•Љ м†Хл©імЬЉл°Ь л≤ДнЛЄ м§АлєДл•Љ нХЬлЛ§.`,
        state: "live",
      };
    }
    if (boundedWave >= 5) {
      return {
        detail: `м§Сл∞Ш лПДмХљ лТ§мЧРлКФ ${stageTwoTitle} нХШлВШлІМ нБђк≤М лВ®лКФлЛ§. лЛ§мЭМ мЛЬнЧШмЭА л≥ім°∞мД†л≥ілЛ§ м£ЉнПђмЩА м∞®м≤ік∞А space ownershipл•Љ мЦЉлІИлВШ мШ§лЮШ мЬ†мІАнХШлКРлГРлЛ§.`,
        state: "primed",
      };
    }
    return {
      detail: `Wave 6 л™Єм≤і лПДмХљмЭД лДШкЄ∞л©і ${stageTwoTitle}мЭі(к∞А) лЛ§мЭМ нБ∞ л≥АмЭік∞А лРЬлЛ§. м§СнЫДл∞ШмЭА мґФк∞А нЦЙм†Х м†Им∞®к∞А мХДлЛИлЭЉ лНФ нБ∞ weapon/body leap нХШлВШл•Љ нЦ•нХі мИШл†інХЬлЛ§.`,
      state: "planned",
    };
  }

  function getShippingRouteLateFinaleRoadmap(build, currentWeapon, lateBreakHeadline, boundedWave) {
    const stageThreeTitle =
      (currentWeapon && currentWeapon.lateAscensionLabel) ||
      (lateBreakHeadline && lateBreakHeadline.title) ||
      "Crown Break";
    if (build.lateAscensionId) {
      return {
        title: stageThreeTitle,
        detail: `${stageThreeTitle}мЭі(к∞А) мЭілѓЄ мЮ†к≤ЉлЛ§. лВ®мЭА Wave 9-12лКФ мГИ мШИмЩЄ мЧЖмЭі мЭі мЛ§л£®мЧ£ нХШлВШл°Ь payoff, proof, refuge cadence, final standл•Љ лБЭкєМмІА л∞АмЦілґЩмЭілКФ finaleлЛ§.`,
        state: "locked",
      };
    }
    if (lateBreakHeadline) {
      return {
        title: stageThreeTitle,
        detail: `${lateBreakHeadline.detail} Wave 9-12лКФ мЭі нЫДл∞Ш нМРнГАмІА нХШлВШлІМ м¶Эл™ЕнХШлКФ к≥†м†Х finaleлЛ§.`,
        state:
          boundedWave >= MAX_WAVES
            ? "locked"
            : boundedWave >= LATE_BREAK_ARMORY_WAVE
              ? "live"
              : "primed",
      };
    }
    return {
      title: stageThreeTitle,
      detail:
        "Wave 8мЧРмДЬ нХШлВШмЭШ нЫДл∞Ш нШХнГЬл•Љ к≥†л•іл©і Wave 9 payoff, Wave 10 proof, Wave 11 cadence, Wave 12 final standл°Ь л∞Фл°Ь лЛЂнЮМлЛ§.",
      state: boundedWave >= LATE_BREAK_ARMORY_WAVE ? "primed" : "planned",
    };
  }

  function getBaseRouteFinaleRoadmap(build, currentWeapon, boundedWave) {
    const doctrineBodyForm = getDoctrineBodyForm(build);
    const dominantFormLabel = doctrineBodyForm
      ? `${getPresentationHeadlineLabel(currentWeapon, boundedWave) || currentWeapon.doctrineFormLabel || currentWeapon.evolutionLabel || CORE_DEFS[build.coreId].label} / ${doctrineBodyForm.label}`
      : getPresentationHeadlineLabel(currentWeapon, boundedWave) ||
        currentWeapon.doctrineFormLabel ||
        currentWeapon.evolutionLabel ||
        CORE_DEFS[build.coreId].label;
    const finalTitle = boundedWave >= DEFAULT_ROUTE_WAVE_COUNT ? "мІІмЭА мКєл¶ђ лЮ©" : "мЩДмД± мЛЬнЧШ";
    if (boundedWave >= DEFAULT_ROUTE_WAVE_COUNT) {
      return {
        title: finalTitle,
        detail: `${dominantFormLabel}мЭі(к∞А) лЯ∞мЭШ лІИмІАлІЙ мЛ§л£®мЧ£мЬЉл°Ь мЮ†к≤ЉлЛ§. лВ®мЭА к±і мГИ к∞Ил¶ЉкЄЄмЭі мХДлЛИлЭЉ Wave 8 proof лТ§ мІІмЭА мКєл¶ђ лЮ©мЧРмДЬ мЭі нШХнГЬк∞А laneмЭД мЦЉлІИлВШ лДУк≤М мУЄмЦі лЛілКФмІА мІБм†С лИДл•ілКФ мЭЉлњРмЭілЛ§.`,
        state: "live",
      };
    }
    if (boundedWave >= DEFAULT_ROUTE_WAVE_COUNT - 1) {
      return {
        title: finalTitle,
        detail: `лЛ§мЭМ м†ХмІАлКФ мГИ мЛЬлМА мШИк≥†к∞А мХДлЛИлЭЉ мЩДмД± мЛЬнЧШмЭілЛ§. Wave 8мЧРмДЬ мЮ†кЄі gun/body lineмЭД л∞Фл°Ь м¶Эл™ЕнХШк≥†, лБЭлВШл©і мІІмЭА мКєл¶ђ лЮ© нХШлВШл°Ь мЭіл≤И мЛ§л£®мЧ£мЭД лНФ мШ§лЮШ л™∞мХДл≥ЄлЛ§.`,
        state: "primed",
      };
    }
    return {
      title: finalTitle,
      detail: "м≤Ђ лђікЄ∞ лПДмХљк≥Љ м∞®м≤і мЮ†кЄИмЭД мІАлВШл©і лВ®лКФ мХљмЖНмЭА нХШлВШлЛ§. Wave 8мЧРмДЬ мЮ†кЄі мЛ§л£®мЧ£мЭД м¶Эл™ЕнХШк≥†, к≤∞к≥Љ мІБм†Д мІІмЭА мКєл¶ђ лЮ©мЬЉл°Ь sweep нП≠мЭД мІБм†С лИДл•ЄлЛ§.",
      state: "planned",
    };
  }

  function getBaseRouteBuildRoadmap(build, weapon = null, waveNumber = 1) {
    const boundedWave = clamp(Math.round(waveNumber || 1), 1, DEFAULT_ROUTE_WAVE_COUNT);
    const currentWeapon = weapon || computeWeaponStats(build);
    const doctrineBodyForm = getDoctrineBodyForm(build);
    const activeForm =
      getPresentationHeadlineLabel(currentWeapon, boundedWave) ||
      (currentWeapon && currentWeapon.doctrineFormLabel) ||
      (currentWeapon && currentWeapon.evolutionLabel) ||
      CORE_DEFS[build.coreId].label;
    const activeBodyLabel = doctrineBodyForm ? doctrineBodyForm.label : null;
    const pathLabel = activeBodyLabel ? `${activeForm} / ${activeBodyLabel}` : activeForm;
    const wave3LeapPreview = getArchitectureWeaponLeapPreview(build, getBastionDoctrineDef(build));
    const previewChassis = wave3LeapPreview && wave3LeapPreview.chassis ? wave3LeapPreview.chassis : null;
    const activeChassis = getChassisBreakpointDef(build);
    const supportSnapshot = getInstalledSupportSnapshot(build);
    const installedSupportIdentity =
      supportSnapshot && supportSnapshot.primary
        ? getSupportSystemIdentitySummary(supportSnapshot.primary.id, supportSnapshot.primary.tier)
        : null;
    const stageOneTitle = build.bastionDoctrineId
      ? activeForm
      : (wave3LeapPreview && wave3LeapPreview.weaponChoice.title) || "м≤Ђ лђікЄ∞ лПДмХљ";
    const stageOneDetail = build.bastionDoctrineId
      ? `${pathLabel}мЭі(к∞А) нШДмЮђ м£Љл†• мЛ§л£®мЧ£мЭілЛ§. лЛ§мЭМ нБ∞ мХљмЖНмЭА Wave 6 м∞®м≤і мЮ†кЄИмЭіл©∞, кЈЄ лТ§ лСР м†ДнИђлКФ мГИ л™Єм≤і л¶ђлУђк≥Љ л≥µкЈА к∞БмЭД м¶Эл™ЕнХШлКФ proof lapмЭі лРЬлЛ§.`
      : wave3LeapPreview
        ? `Wave ${ARCHITECTURE_DRAFT_WAVE}мЧРмДЬ ${wave3LeapPreview.weaponChoice.title}мЭД(л•Љ) л®Љм†А лґЩмЧђ м≤Ђ м£ЉнПђ лПДмХљмЭД лІМлУ†лЛ§. supportлВШ мЪімШБ нМ®нВ§мІАлКФ мИ®кЄ∞к≥† мЭі лђікЄ∞ л≥АнЩФлІМ л®Љм†А м†ДмЮ•мЧР лВ®кЄілЛ§.`
        : `Wave ${ARCHITECTURE_DRAFT_WAVE}мЧРмДЬ м≤Ђ м£ЉнПђ лПДмХљмЭД лґЩмЧђ лєИ мД†м≤і кµђк∞ДмЭД лБЭлВЄлЛ§.`;
    const stageOneState = build.bastionDoctrineId
      ? "locked"
      : boundedWave >= ARCHITECTURE_DRAFT_WAVE
        ? "primed"
        : "planned";
    const stageTwoTitle =
      (activeChassis && (activeChassis.label || activeChassis.title)) ||
      (previewChassis && (previewChassis.label || previewChassis.title)) ||
      "м≤Ђ м∞®м≤і мЮ†кЄИ";
    let stageTwoDetail =
      "Wave 6мЧРмДЬлКФ м∞®м≤і мЮ†кЄИлІМ л®Љм†А лґЩмЧђ dive, hold, exit л¶ђлУђмЭД лСР л≤ИмЭШ proof lapмЬЉл°Ь л®Љм†А кµ≥нЮМлЛ§.";
    let stageTwoState = "planned";
    if (activeChassis) {
      stageTwoDetail = installedSupportIdentity
        ? `${stageTwoTitle} м∞®м≤ік∞А proofл•Љ нЖµк≥ЉнЦИк≥† ${installedSupportIdentity.payoffValue}к∞А к∞ЩмЭА мЛ§л£®мЧ£мЭД лНФ лДУк≤М лѓЉлЛ§.`
        : `${stageTwoTitle} м∞®м≤ік∞А мЮ†к≤ЉлЛ§. мЭім†Ь Wave 6-7 proof lapмЭА мЭі л™Єм≤і л¶ђлУђлІМ мЛЬнЧШнХЬлЛ§.`;
      stageTwoState = "locked";
    } else if (boundedWave >= 5) {
      stageTwoDetail = `${stageTwoTitle}мЭі(к∞А) лЛ§мЭМ нБ∞ мХљмЖНмЭілЛ§. Wave 6мЧРмДЬлКФ м∞®м≤ілІМ л®Љм†А мЮ†к∞А mid-run identityл•Љ нХЬ мґХмЬЉл°Ь мДЄмЪілЛ§.`;
      stageTwoState = "primed";
    }
    const baseRouteFinale = getBaseRouteFinaleRoadmap(build, currentWeapon, boundedWave);
    const steps = [
      createRoadmapStep("I", stageOneTitle, stageOneDetail, stageOneState),
      createRoadmapStep("II", stageTwoTitle, stageTwoDetail, stageTwoState),
      createRoadmapStep("III", baseRouteFinale.title, baseRouteFinale.detail, baseRouteFinale.state),
    ];
    const nextStep = steps.find((step) => step.state !== "locked") || steps[2];
    const prompt =
      nextStep && nextStep.state !== "locked"
        ? `${pathLabel}. лЛ§мЭМ нБ∞ м†РнФДлКФ ${nextStep.title}мЭіл©∞, ${nextStep.detail}`
        : `${pathLabel}. gun/body мЛ§л£®мЧ£мЭі л™®лСР мЮ†к≤® лВ®мЭА кµђк∞ДмЭА Wave 8 proofмЩА мІІмЭА мКєл¶ђ лЮ©мЧРмДЬ мЭі нШХнГЬл•Љ мШ§лЮШ м¶Эл™ЕнХШлКФ мЭЉлњРмЭілЛ§.`;
    return {
      pathLabel,
      activeForm,
      doctrineTag: "ROUTE",
      prompt,
      note: `${steps[0].title} -> ${steps[1].title} -> ${steps[2].title}`,
      steps,
    };
  }

  function getBuildRoadmap(build, weapon = null, waveNumber = 1) {
    build = getSanitizedConsolidatedBuild(build);
    if (CONSOLIDATED_12_WAVE_ROUTE) {
      return getBaseRouteBuildRoadmap(build, weapon, waveNumber);
    }
    const boundedWave = clamp(
      Math.round(waveNumber || 1),
      1,
      CONSOLIDATED_12_WAVE_ROUTE ? DEFAULT_ROUTE_WAVE_COUNT : MAX_WAVES + POST_CAPSTONE_WAVE_COUNT
    );
    const doctrine = getBastionDoctrineDef(
      (build && (build.bastionDoctrineId || build.architectureForecastId)) || build
    );
    const pursuit = getDoctrineForgePursuitDef(doctrine || build);
    const currentWeapon = weapon || computeWeaponStats(build);
    const doctrineBodyForm = getDoctrineBodyForm(build);
    const doctrineForm = currentWeapon && currentWeapon.doctrineFormLabel ? currentWeapon.doctrineFormLabel : null;
    const lateBreakHeadline = getLateBreakHeadline(build && build.lateBreakProfileId);
    const activeForm =
      getPresentationHeadlineLabel(currentWeapon, boundedWave) ||
      (currentWeapon && currentWeapon.lateFieldConvergenceLabel) ||
      doctrineForm ||
      CORE_DEFS[build.coreId].label;
    const activeBodyLabel = doctrineBodyForm ? doctrineBodyForm.label : null;
    const pathLabel = doctrine
      ? `${doctrine.label} ¬Ј ${activeForm}${activeBodyLabel ? ` / ${activeBodyLabel}` : ""}`
      : `${CORE_DEFS[build.coreId].label} ¬Ј ${activeForm}`;
    const wave3LeapPreview = getArchitectureWeaponLeapPreview(build, doctrine);
    const stageOneTitle =
      (build.bastionDoctrineId && (currentWeapon.doctrineFormLabel || activeForm)) ||
      (wave3LeapPreview && wave3LeapPreview.weaponChoice.title) ||
      (doctrine ? doctrine.label : "Monster Form Lock");
    const stageOneDetail = build.bastionDoctrineId
      ? `${currentWeapon.doctrineFormLabel || activeForm}${
          activeBodyLabel ? ` / ${activeBodyLabel}` : ""
        }мЭі(к∞А) нШДмЮђ body/gun мЛ§л£®мЧ£мЭілЛ§. мЭінЫД нПђмІАлКФ мЭі нШХнГЬл•Љ лНФ к≥Љк≤©нХШк≤М л∞Ак±∞лВШ мХљм†РмЭД л©ФмЪ∞лКФ м™љмЬЉл°ЬлІМ мЧіл¶∞лЛ§.`
      : wave3LeapPreview
        ? `Wave ${ARCHITECTURE_DRAFT_WAVE}мЧРмДЬ ${wave3LeapPreview.weaponChoice.title}мЭД(л•Љ) л®Љм†А лґЩмЧђ м≤Ђ м£ЉнПђ лПДмХљмЭД лІМлУ†лЛ§. Wave 6мЧРмДЬлКФ ${(wave3LeapPreview.chassis && wave3LeapPreview.chassis.title) || "м∞®м≤і break"}л•Љ лНФнХі л™Єм≤і л¶ђлУђкєМмІА нЩХм†ХнХЬлЛ§.`
        : `Wave ${ARCHITECTURE_DRAFT_WAVE}мЧРмДЬ кµРл¶ђл•Љ мЮ†к∞А м≤Ђ monster formк≥Љ chassis laneмЭД мЧ∞лЛ§.`;
    const stageOneState = build.bastionDoctrineId
      ? "locked"
      : boundedWave >= ARCHITECTURE_DRAFT_WAVE
        ? "primed"
        : "planned";

    const stageTwoTitle =
      (currentWeapon && currentWeapon.capstoneLabel) ||
      getDoctrineLateCapstoneLabel(doctrine) ||
      (doctrine ? `${doctrine.label} Apex` : "Midform Spike");
    let stageTwoDetail = "м§Сл∞Ш marked eliteл•Љ лФ∞лЭЉ лЛ§мЭМ weapon/body breakл•Љ к∞Хм†Ьл°Ь мЧ∞лЛ§.";
    let stageTwoState = "planned";
    if (CONSOLIDATED_12_WAVE_ROUTE) {
      const shippingCapstoneRoadmap = getShippingRouteCapstoneRoadmap(
        build,
        stageTwoTitle,
        boundedWave
      );
      stageTwoDetail = shippingCapstoneRoadmap.detail;
      stageTwoState = shippingCapstoneRoadmap.state;
    } else if (build.doctrineCapstoneId) {
      stageTwoDetail = `${stageTwoTitle}мЭі(к∞А) мЭілѓЄ мЮ†к≤ЉлЛ§. Wave 9-12лКФ мГИ кЈЬмєЩ нХЩмКµл≥ілЛ§ мЭі м§Ск∞Д нШХнГЬл°Ь laneмЭД м∞Ґк≥† eliteл•Љ мґФм†БнХШлКФ кµђк∞ДмЭілЛ§.`;
      stageTwoState = "locked";
    } else if (build.doctrineChaseClaimed) {
      stageTwoDetail = `лЛ§мЭМ live ascension cacheк∞А ${stageTwoTitle} мЩДмД± мІБм†ДкєМмІА мЧіл†§ мЮИлЛ§. marked eliteл•Љ л®Љм†А м∞ҐмЦі body spliceл•Љ нЪМмИШнХімХЉ нХЬлЛ§.`;
      stageTwoState = "primed";
    } else if (build.doctrinePursuitCommitted && pursuit) {
      stageTwoDetail = `Wave 6-8 marked eliteмЧРмДЬ ${pursuit.shardLabel} ${build.doctrinePursuitProgress}/${pursuit.goal}к∞Ьл•Љ нЪМмИШнХШл©і ${stageTwoTitle}мЭі(к∞А) м¶ЙмЛЬ лЛєк≤®мІДлЛ§.`;
      stageTwoState = "live";
    } else if (build.overcommitUnlocked && pursuit) {
      stageTwoDetail = `contraband salvageл•Љ м†ДлґА м±Щк≤ЉлЛ§. мЭім†Ь лЛ§мЭМ Field CacheмЭШ greed лМАмЛ† ${stageTwoTitle} pursuitл•Љ к±Єл©і marked elite ${pursuit.goal}нЪМл°Ь м°∞кЄ∞ мЩДмД±мЭД лЕЄл¶і мИШ мЮИлЛ§.`;
      stageTwoState = "primed";
    } else if (build.overcommitResolved) {
      stageTwoDetail = `${stageTwoTitle} м°∞кЄ∞ chaseлКФ лЛЂнШФлЛ§. лВ®мЭА лЯ∞мЧРмДЬлКФ live ascension cacheл°ЬлІМ мХИм†ДнХШк≤М лБМмЦімЩАмХЉ нХЬлЛ§.`;
      stageTwoState = "missed";
    } else if (pursuit) {
      stageTwoDetail = `Wave 5 contraband salvageл•Љ м†ДлґА нЪМмИШнХШл©і ${stageTwoTitle} pursuitк∞А мЧіл¶∞лЛ§. мЛ§нМ®нХШл©і м§Сл∞Ш breakлКФ лТ§л°Ь л∞Ал¶∞лЛ§.`;
    }

    let stageThreeTitle =
      (CONSOLIDATED_12_WAVE_ROUTE
        ? null
        : (currentWeapon && currentWeapon.afterburnDominionLabel) ||
          (currentWeapon && currentWeapon.afterburnOverdriveLabel) ||
          (currentWeapon && currentWeapon.lateAscensionLabel) ||
          null) ||
      (lateBreakHeadline && lateBreakHeadline.title) ||
      (CONSOLIDATED_12_WAVE_ROUTE ? "мЩДмД± мЛЬнЧШ" : "Crown Break");
    let stageThreeDetail = lateBreakHeadline
      ? CONSOLIDATED_12_WAVE_ROUTE
        ? "Wave 8 proofмЩА мІІмЭА мКєл¶ђ лЮ©лІМ лВ®лКФлЛ§. мГИ мШИмЩЄ лґДкЄ∞лКФ лЛЂк≥†, мІАкЄИкєМмІА мЮ†кЈЉ мЛ§л£®мЧ£мЭД л∞Фл°Ь мШ§лЮШ м¶Эл™ЕнХЬлЛ§."
        : `${lateBreakHeadline.detail} Wave 8 мЭінЫДмЧРлКФ мЭі к≥ДлЛ® нХШлВШлІМ лВ®к≥† live ascensionмЭілВШ Afterburn мШИмЩЄлКФ мЧіл¶ђмІА мХКлКФлЛ§.`
      : CONSOLIDATED_12_WAVE_ROUTE
        ? "Wave 8 proofмЩА мІІмЭА мКєл¶ђ лЮ©лІМ лВ®лКФлЛ§. мГИ мЛЬлМА мШИк≥† мЧЖмЭі мЮ†кЄі gun/body lineмЭД лБЭкєМмІА лИМлЯђ л≥ЄлЛ§."
        : "Wave 8 Late Break ArmoryмЧРмДЬ нХШлВШмЭШ late-form staircaseл•Љ к≥†л•іл©і Wave 9-10 payoff band -> Wave 11 refuge run -> Wave 12 finaleл°Ь к≥†м†ХлРЬлЛ§.";
    let stageThreeState = boundedWave >= LATE_BREAK_ARMORY_WAVE ? "primed" : "planned";
    if (CONSOLIDATED_12_WAVE_ROUTE) {
      const baseRouteFinale = getBaseRouteFinaleRoadmap(build, currentWeapon, boundedWave);
      stageThreeTitle = baseRouteFinale.title;
      stageThreeDetail = baseRouteFinale.detail;
      stageThreeState = baseRouteFinale.state;
    } else if (build.afterburnDominionId) {
      stageThreeDetail = `${stageThreeTitle}мЭі(к∞А) мЭілѓЄ мµЬмҐЕ мІАл∞∞ нШХнГЬл°Ь мЮ†к≤ЉлЛ§. лВ®мЭА bracketмЭА нМРлПИл≥ілЛ§ мХХлПДк∞РмЭі л®Љм†А мШ§лКФ victory lapмЭілЛ§.`;
      stageThreeState = "locked";
    } else if (build.afterburnOverdriveId) {
      stageThreeDetail = `${stageThreeTitle} overdriveк∞А мЉЬм°МлЛ§. лЛ§мЭМ Dominion BreakлІМ нЪМмИШнХШл©і лІИмІАлІЙ bracket нХШлВШк∞А мКєл¶ђ лЮ©мЬЉл°Ь мЮђнОЄлРЬлЛ§.`;
      stageThreeState = "live";
    } else if (build.lateAscensionId) {
      stageThreeDetail = `${stageThreeTitle} body splitмЭі мЮ†к≤ЉлЛ§. Afterburn elite cacheл°Ь лВ®мЭА enduranceл•Љ overdrive мЛ§л£®мЧ£кєМмІА лНФ л∞А мИШ мЮИлЛ§.`;
      stageThreeState = boundedWave > MAX_WAVES ? "live" : "locked";
    } else if (lateBreakHeadline) {
      stageThreeState =
        boundedWave >= MAX_WAVES
          ? "locked"
          : boundedWave >= LATE_BREAK_ARMORY_WAVE
            ? "live"
            : "primed";
    }

    const steps = [
      createRoadmapStep("I", stageOneTitle, stageOneDetail, stageOneState),
      createRoadmapStep("II", stageTwoTitle, stageTwoDetail, stageTwoState),
      createRoadmapStep("III", stageThreeTitle, stageThreeDetail, stageThreeState),
    ];
    const nextStep = steps.find((step) => step.state !== "locked") || steps[2];
    const prompt =
      nextStep && nextStep.state !== "locked"
        ? `${pathLabel}. нШДмЮђ form trackмЭШ лЛ§мЭМ м†РнФДлКФ ${nextStep.title}мЭіл©∞, ${nextStep.detail}`
        : `${pathLabel}. мДЄ лЛ®к≥Д form trackмЭі л™®лСР мЮ†к≤® лВ®мЭА мЧ∞м†ДмЭА нШДмЮђ endformмЭД мШ§лЮШ м¶Эл™ЕнХШлКФ кµђк∞ДмЭілЛ§.`;
    return {
      pathLabel,
      activeForm,
      doctrineTag: doctrine ? doctrine.tag : "CORE",
      prompt,
      note: `${steps[0].title} -> ${steps[1].title} -> ${steps[2].title}`,
      steps,
    };
  }

  function createRoadmapMarkup(roadmap) {
    if (!roadmap) {
      return "";
    }
    const activeStep =
      roadmap.steps.find((step) => step.state === "live") ||
      roadmap.steps.find((step) => step.state === "primed") ||
      roadmap.steps.find((step) => step.state === "planned") ||
      roadmap.steps[roadmap.steps.length - 1] || null;
    return `
      <div class="summary-head">
        <strong>нШДмЮђ к≥ДмХљ</strong>
        <span class="summary-chip ${activeStep && activeStep.state === "live" ? "summary-chip--hot" : ""}">${roadmap.doctrineTag}</span>
      </div>
      ${createBaseRouteStatusStripMarkup({
        leadLabel: "м¶ЙмЛЬ м¶Эл™Е",
        leadValue: activeStep ? activeStep.title : roadmap.activeForm,
        titleLabel: "нШДмЮђ нШХнГЬ",
        titleValue: roadmap.pathLabel,
        headlineFirst: true,
      })}
    `;
  }

  function getShippingLadderSteps(build, weapon = null, waveNumber = 1) {
    const boundedWave = clamp(Math.round(waveNumber || 1), 1, DEFAULT_ROUTE_WAVE_COUNT);
    const currentWeapon = weapon || computeWeaponStats(build);
    const dominantForm = getDominantFormSummary(build, currentWeapon, boundedWave);
    const chassis = getChassisBreakpointDef(build);
    const supportSnapshot = getInstalledSupportSnapshot(build);
    const supportIdentity =
      supportSnapshot && supportSnapshot.primary
        ? getSupportSystemIdentitySummary(supportSnapshot.primary.id, supportSnapshot.primary.tier)
        : null;
    const stageState = (start, end = start) => {
      if (boundedWave > end) {
        return "locked";
      }
      if (boundedWave >= start) {
        return "live";
      }
      return boundedWave + 1 >= start ? "primed" : "planned";
    };
    return [
      {
        label: "START",
        title: "мХљнХЬ мЛЬмЮС",
        state: boundedWave >= 3 ? "locked" : "live",
        detail:
          boundedWave >= 3
            ? "лєИ мД†м≤і кµђк∞ДмЭА лБЭлВђлЛ§. мЭім†Ь лЯ∞мЭШ нБ∞ мХљмЖНмЭА л™Єм≤і мЮ†кЄИк≥Љ нЫДкЄ∞ м†РнЩФлІМ лВ®лКФлЛ§."
            : "м≤ШмЭМ лСР мЫ®мЭілЄМлКФ нХЬ м§Д нЩФмД†мЬЉл°Ь л≤ДнЛілЛ§. лѓЄмВђмЭЉк≥Љ л≥ім°∞ мЧ∞мґЬмЭА лЛЂмХД лСРк≥† Wave 3 лђікЄ∞ лПДмХљмЧР нЮШмЭД л™®мЭАлЛ§.",
      },
      {
        label: "лПДмХљ",
        title: boundedWave >= 3 ? dominantForm.label : "м≤Ђ лђікЄ∞ лПДмХљ",
        state: stageState(3),
        detail:
          boundedWave >= 3
            ? `${dominantForm.label}мЭі м≤Ђ м£ЉнПђ лПДмХљмЬЉл°Ь мЮ†к≤ЉлЛ§. мЭі нЩФлІЭмЭі лЯ∞мЭШ кЄ∞м§АмЭі лРШл©∞, лЛ§мЭМ нБ∞ мХљмЖНмЭА Wave 6 л™Єм≤і мЮ†кЄИмЭілЛ§.`
            : "Wave 3 нХЬ мЮ•мЬЉл°Ь м≤Ђ нПђлђЄмЭД нБђк≤М л≤Мл¶∞лЛ§. мЮСмЭА м°∞мЬ®мЭА лТ§л°Ь мИ®кЄ∞к≥† мЭі лђікЄ∞ л≥АнЩФлІМ л®Љм†А лШРл†ЈнХШк≤М мЭљнЮИк≤М лСФлЛ§.",
      },
      {
        label: "л∞©нШЄ",
        title: chassis ? chassis.label : "л∞©нШЄ мХљмЖН",
        state: stageState(6),
        detail: chassis
          ? supportIdentity
            ? `${chassis.label} м∞®м≤ік∞А proofл•Љ нЖµк≥ЉнЦИк≥† ${supportIdentity.payoffValue}к∞А к∞ЩмЭА мЛ§л£®мЧ£мЭД лНФ лДУк≤М л∞АмЦілґЩмЭЄлЛ§.`
            : `${chassis.label} м∞®м≤ік∞А м≤Ђ л∞©нШЄ мХљмЖНмЬЉл°Ь мЮ†кЄілЛ§. Wave 6-7мЭА мЭі л™Єм≤і л¶ђлУђлІМ м¶Эл™ЕнХЬлЛ§.`
          : "Wave 6мЧРмДЬлКФ м∞®м≤і мЮ†кЄИлІМ л®Љм†А лґЩмЭЄлЛ§. Wave 6-7мЭі кЈЄ л™Єм≤і proofл•Љ лІ°лКФлЛ§.",
      },
    ];
  }

  function getShippingLadderFocus(build, weapon = null, waveNumber = 1) {
    const steps = getShippingLadderSteps(build, weapon, waveNumber);
    return (
      steps.find((step) => step.state === "live") ||
      steps.find((step) => step.state === "primed") ||
      steps.find((step) => step.state === "planned") ||
      steps[steps.length - 1]
    );
  }

  function createShippingLadderMarkup(build, weapon = null, waveNumber = 1) {
    const boundedWave = clamp(Math.round(waveNumber || 1), 1, DEFAULT_ROUTE_WAVE_COUNT);
    const focus = getShippingLadderFocus(build, weapon, boundedWave);
    const dominantForm = getDominantFormSummary(build, weapon || computeWeaponStats(build), boundedWave);
    const proofWindow = getImmediateProofWindowSummary(build, boundedWave);
    return `
      <div class="summary-head">
        <strong>лЯ∞ мГБнГЬ</strong>
        <span class="summary-chip ${focus.state === "live" ? "summary-chip--hot" : ""}">${focus.windowLabel || focus.label}</span>
      </div>
      ${createBaseRouteStatusStripMarkup({
        leadLabel: "м¶ЙмЛЬ м¶Эл™Е",
        leadValue: proofWindow.label,
        titleLabel: "нШДмЮђ нШХнГЬ",
        titleValue: dominantForm.label,
        headlineFirst: true,
      })}
    `;
  }

