    const focusPrompt = useBaseRouteContract
      ? state.pendingFinalForge
        ? `${dominantFormSummary.label}л°Ь мЭіл≤И лЯ∞мЭШ лІИмІАлІЙ мЛ§л£®мЧ£мЭД к≥†м†ХнХЬлЛ§.`
        : riderStep
          ? `${dominantFormSummary.label} мШЖмЧР л≤ДнЛ∞лКФ мД† нХЬ м§ДлІМ лНФнХЬлЛ§.`
          : `${focusTitle} нХШлВШл°Ь лЛ§мЭМ м†ДнИђмЭШ нЩФл©імЭД л∞ФкЊЉлЛ§.`
      : state.pendingFinalForge
        ? `${dominantFormSummary.label}л•Љ мЭіл≤И 12-wave spineмЭШ мµЬмҐЕ мЛ§л£®мЧ£мЬЉл°Ь ліЙмЭЄнХЬлЛ§.`
        : riderStep
        ? `${dominantFormSummary.label} мЬДмЧР rider нХЬ мЮ•лІМ мЦєк≥† л∞Фл°Ь лЛ§мЭМ м†ДнИђ askл•Љ л≤ДнЛілЛ§.`
          : `${dominantFormSummary.label} лЛ§мЭМмЧР к∞АмЮ• нБђк≤М м†ДмЮ•мЭД л∞ФкњА л≥АмЭі нХШлВШлІМ л®Љм†А к≥†л•ЄлЛ§.`;
